          [STORAGE_KEY_RELEASE_DATE_FORMAT]: "YYYY-MM-DD",
          [STORAGE_KEY_REMOVE_DATE_ADDED]: "false",
          [STORAGE_KEY_INCLUDE_SONG_STATS]: "true",
