          [STORAGE_KEY_SHOW_LIKE_BUTTON]: "false",
          [STORAGE_KEY_LIKE_BUTTON_CONFIG]: JSON.stringify({ trackRows: true, nowPlayingBar: true, nowPlayingView: true }),
