                    const viewportWidth = window.innerWidth;
                    const margin = 8;

                    tooltip.style.top = `${buttonRect.top - tooltipRect.height - 8}px`;
                    let idealLeft = buttonRect.left + (buttonRect.width / 2) - (tooltipRect.width / 2);
                    
                    if (idealLeft < margin) idealLeft = margin;
